// Declaring an async function
async function fetchUser(id) {
  const response = await fetch(`/api/users/${id}`);
  const user     = await response.json();
  return user; // the async function wraps this in Promise.resolve(user)
}

// Arrow function form — same behaviour
const fetchUser = async (id) => {
  const response = await fetch(`/api/users/${id}`);
  return response.json();
};

// Consuming: fetchUser() returns a Promise
fetchUser(1).then(user => console.log(user.name));

// Or with await at the call site (inside another async function):
async function main() {
  const user = await fetchUser(1);
  console.log(user.name);
}

// ❌ Promise chain — hard to follow conditional logic
function loadDashboard(userId) {
  return fetchUser(userId)
    .then(user => {
      if (!user.active) return Promise.reject(new Error('Inactive user'));
      return fetchPosts(user.id);
    })
    .then(posts => {
      return Promise.all(posts.map(p => fetchCommentCount(p.id)))
        .then(counts => posts.map((p, i) => ({ ...p, commentCount: counts[i] })));
    })
    .then(enrichedPosts => ({ enrichedPosts }))
    .catch(err => console.error(err));
}

// ✅ async/await — reads like synchronous code
async function loadDashboard(userId) {
  try {
    const user = await fetchUser(userId);
    if (!user.active) throw new Error('Inactive user');

    const posts    = await fetchPosts(user.id);
    const counts   = await Promise.all(posts.map(p => fetchCommentCount(p.id)));
    const enriched = posts.map((p, i) => ({ ...p, commentCount: counts[i] }));
    return { enriched };
  } catch (err) {
    console.error(err);
  }
}

// Step-by-step implementation
async function getDashboardData(userId) {
  // Step 1: sequential fetch (each depends on the previous)
  const user  = await fetchUser(userId);
  const prefs = await fetchPreferences(user.settingsId);

  // Step 2: parallel fetch (posts and followers are independent)
  const [posts, followers] = await Promise.all([
    fetchPosts(userId),
    fetchFollowers(userId),
  ]);

  // Step 3: conditional async logic
  let recommendations = [];
  if (prefs.showRecommendations) {
    recommendations = await fetchRecommendations(userId);
  }

  return { user, prefs, posts, followers, recommendations };
}

async function getPost(id) {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`);

  if (!response.ok) {
    throw new Error(`Failed to fetch post: HTTP ${response.status}`);
  }

  return response.json(); // returns a Promise — await unwraps it implicitly
}

// Usage:
const post = await getPost(1);
console.log(post.title);

async function fetchWithRetry(url, { retries = 3, delayMs = 500 } = {}) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const res = await fetch(url);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return await res.json();
    } catch (err) {
      if (attempt === retries) throw err; // last attempt — re-throw
      // Wait before retrying (exponential back-off)
      await new Promise(resolve => setTimeout(resolve, delayMs * attempt));
      console.warn(`Attempt ${attempt} failed, retrying…`);
    }
  }
}

const data = await fetchWithRetry('/api/fragile-endpoint', { retries: 3 });

import { useState, useEffect } from 'react';

function ProductList({ page }) {
  const [products, setProducts] = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [error,    setError]    = useState(null);

  useEffect(() => {
    // useEffect callback cannot be async — define inner function
    const controller = new AbortController();

    async function load() {
      setLoading(true);
      setError(null);
      try {
        const res = await fetch(
          `/api/products?page=${page}`,
          { signal: controller.signal }
        );
        if (!res.ok) throw new Error(`Server error: ${res.status}`);
        const data = await res.json();
        setProducts(data.items);
      } catch (err) {
        if (err.name === 'AbortError') return; // unmount — ignore
        setError(err.message);
      } finally {
        setLoading(false);
      }
    }

    load();
    return () => controller.abort(); // cancel on page change or unmount
  }, [page]);

  if (loading) return <p>Loading products…</p>;
  if (error)   return <p className="error">Error: {error}</p>;
  return (
    <ul>
      {products.map(p => (
        <li key={p.id}>{p.name} — ${p.price}</li>
      ))}
    </ul>
  );
}

// ❌ Sequential — total time = time(a) + time(b)
async function bad() {
  const a = await fetchA(); // waits for A before starting B
  const b = await fetchB();
  return [a, b];
}

// ✅ Parallel — total time = max(time(a), time(b))
async function good() {
  const [a, b] = await Promise.all([fetchA(), fetchB()]);
  return [a, b];
}

// ❌ async effect — returns a Promise, not a cleanup function
useEffect(async () => {
  const data = await fetchData();
  setData(data);
}, []);

// ✅ Define and invoke an inner async function
useEffect(() => {
  async function load() {
    const data = await fetchData();
    setData(data);
  }
  load();
}, []);

