// ❌ Errors silently vanish
async function load() {
  try {
    return await fetchData();
  } catch (e) {} // swallows everything — caller has no idea it failed
}

// ✅ At minimum, log and re-throw
async function load() {
  try {
    return await fetchData();
  } catch (e) {
    console.error('load failed:', e);
    throw e; // let caller decide how to handle
  }
}

// ❌ forEach ignores returned Promises — the awaits are never awaited
ids.forEach(async id => {
  const data = await fetchItem(id); // fires but nothing waits for it
  process(data);
});

// ✅ for...of — processes one at a time (predictable, uses less memory)
for (const id of ids) {
  const data = await fetchItem(id);
  process(data);
}

// ✅ Promise.all — all in parallel (fastest, but can overwhelm server)
const results = await Promise.all(ids.map(id => fetchItem(id)));

// ✅ Batched parallel — concurrency cap of 5
async function fetchBatched(ids, concurrency = 5) {
  const results = [];
  for (let i = 0; i < ids.length; i += concurrency) {
    const batch = ids.slice(i, i + concurrency);
    results.push(...await Promise.all(batch.map(id => fetchItem(id))));
  }
  return results;
}
